public InventAgingTmp findOrCreate(
    ItemGroupId         _itemGroupId,
    ItemId              _itemId,
    ItemName            _itemName,
    UnitOfMeasureSymbol _unit,
    InventDim           _inventDim)

{
    InventAgingTmp                  localLine;
    InventTrans                     inventTransloc, inventTransissue;
    InventDim                       inventdimloc;
    InventBatch                     inventbatch;

    //DimensionAttributeValueSetStorage   valueSetStorage = new DimensionAttributeValueSetStorage();
    localLine = next findOrCreate(_itemGroupId,_itemId,_itemName,_unit,_inventDim);

    //select firstonly DimensionSetName from  inventAgingStorage
    //    where inventAgingStorage.TransactionId == localLine.createdTransactionId;

    select * from inventTransloc
        join inventdimloc
         where inventdimloc.inventDimId == inventTransloc.inventDimId
            && inventdimloc.inventBatchId == _inventDim.inventBatchId
            && inventTransloc.ItemId == _itemId;

    select firstonly inventbatch 
        where inventbatch.itemId == _itemId 
            && inventbatch.inventBatchId == _inventDim.inventBatchId;


    localLine.prodDate      = inventbatch.prodDate;
    localLine.expDate       = inventbatch.expDate;
    localLine.DatePhysical  = inventTransloc.DatePhysical; //10\10\2021;//

    return  localLine;

}
